  ('aboriginal-6e11b43e-moex-00232', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-112-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '關於行政罰之行為人，下列敘述何者正確？', '["行政機關不受行政處罰", "非法人團體因無法人格，不受行政罰", "私法人董事因執行職務故意使私法人違反行政法上義務且應受處罰時，應同受處罰", "於共同違反行政法上義務之情形，若因身分得減輕處罰時，其無此身分者亦得減輕"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "0742f2f54d5c", "answer_pdf_sha1": "107658906250", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "506", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00233', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-112-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '關於行政執行之敘述，下列何者正確？', '["負有行為義務而不為，其行為不能由他人代為履行者，得處怠金", "行為人違規經主管機關科處罰鍰後死亡者，不得強制執行", "行政法上不行為義務由行政機關委託第三人履行者，為代履行", "在義務人不履行行政法上之義務下，均由原處分機關為強制執行"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "0742f2f54d5c", "answer_pdf_sha1": "107658906250", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "506", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00234', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-112-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '機關作成下列何種行為應遵守行政程序法之程序規定？', '["臺北市政府處理陳情", "檢察官偵查犯罪", "監察院對公務員彈劾", "臺北市議會制定自治條例"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "0742f2f54d5c", "answer_pdf_sha1": "107658906250", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "506", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00235', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-112-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '關於行政救濟之敘述，下列何者錯誤？', '["撤銷訴訟進行中，因原處分已執行完畢，如原告仍有受確認判決之法律上利益時，原告仍可將 撤銷訴訟變更確認處分違法之訴訟", "行政機關就其行政處分之作成，依法雖有裁量權，但其裁量權有濫用權力之情形，行政法院仍 可撤銷該行政處分", "除法律有特別規定外，撤銷訴訟須先經訴願程序始得合法提起", "人民起訴請求行政機關給付金錢之行政訴訟，應先經訴願程序，始得為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "0742f2f54d5c", "answer_pdf_sha1": "107658906250", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "506", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
